17	const basePremiumFor = (item: Item): number => BASE_PREMIUM[item.type];
18	
19	const COMPONENT_BLOCK_SIZE = 3;
20	const COMPONENT_BLOCK_PREMIUM = 60;
21	
22	const groupByType = (items: Item[]): Item[][] => {
23	  const groups = new Map<string, Item[]>();
24	  for (const item of items) {
25	    const group = groups.get(item.type) ?? [];
26	    group.push(item);
27	    groups.set(item.type, group);
28	  }
29	  return [...groups.values()];
30	};
31	
32	const sumOfBasePremiums = (items: Item[]): number =>
33	  items.reduce((sum, item) => sum + basePremiumFor(item), 0);
34	
35	const basePremiumForGroup = (group: Item[]): number =>
36	  group.length === COMPONENT_BLOCK_SIZE
37	    ? COMPONENT_BLOCK_PREMIUM
38	    : sumOfBasePremiums(group);
39	
40	const totalBasePremium = (items: Item[]): number =>
41	  groupByType(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);
42	
43	const CURSE_SURCHARGE_RATE = 0.5;
44	const HIGH_ENCHANTMENT_RATE = 0.3;
45	const HIGH_ENCHANTMENT_THRESHOLD = 5;
46	const FIRST_INSURANCE_RATE = 0.1;
47	const LOYALTY_DISCOUNT_RATE = -0.2;
48	const LOYALTY_YEARS_THRESHOLD = 2;
49	const FOLLOW_UP_DISCOUNT_RATE = -0.15;
50	
51	type PolicyContext = { customer: Customer; isFollowUp: boolean };
52	
53	const isCursed = (item: Item): boolean => item.cursed === true;
54	const isHighlyEnchanted = (item: Item): boolean =>
55	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
56	
57	type Modifier<T> = { applies: (subject: T) => boolean; rate: number };
58	
59	const sumApplicableRates = <T>(modifiers: Modifier<T>[], subject: T): number =>
60	  modifiers.reduce((sum, { applies, rate }) => sum + (applies(subject) ? rate : 0), 0);
61	
62	const ITEM_SURCHARGES: Modifier<Item>[] = [
63	  { applies: isCursed, rate: CURSE_SURCHARGE_RATE },
64	  { applies: isHighlyEnchanted, rate: HIGH_ENCHANTMENT_RATE },
65	];
66	
67	const isFirstInsurance = (_ctx: PolicyContext): boolean => true;
68	const isLoyalCustomer = (ctx: PolicyContext): boolean =>
69	  ctx.customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
70	const isFollowUpContract = (ctx: PolicyContext): boolean => ctx.isFollowUp;
71	
72	const POLICY_MODIFIERS: Modifier<PolicyContext>[] = [
73	  { applies: isFirstInsurance, rate: FIRST_INSURANCE_RATE },
74	  { applies: isLoyalCustomer, rate: LOYALTY_DISCOUNT_RATE },
75	  { applies: isFollowUpContract, rate: FOLLOW_UP_DISCOUNT_RATE },
76	];
77	
78	const policyAdjustment = (baseTotal: number, ctx: PolicyContext): number =>
79	  baseTotal * sumApplicableRates(POLICY_MODIFIERS, ctx);
80	
81	const itemSurchargeFor = (item: Item): number =>
82	  basePremiumFor(item) * sumApplicableRates(ITEM_SURCHARGES, item);
83	
84	const itemSurchargesTotal = (items: Item[]): number =>
85	  items.reduce((sum, item) => sum + itemSurchargeFor(item), 0);
86	
87	const premiumFor = (items: Item[], ctx: PolicyContext): number => {
88	  const baseTotal = totalBasePremium(items);
89	  return Math.ceil(
90	    baseTotal +
91	      itemSurchargesTotal(items) +
92	      policyAdjustment(baseTotal, ctx) +
93	      PROCESSING_FEE,
94	  );
95	};
96	
97	const resultFor = (step: QuoteStep, ctx: PolicyContext) => ({
98	  premium: premiumFor(step.items, ctx),
99	});
100	
101	export const runScenario = (input: unknown): unknown => {
102	  const scenario = input as Scenario;
103	  return {
104	    results: scenario.steps.map((step, index) =>
105	      resultFor(step, { customer: scenario.customer, isFollowUp: index > 0 }),
106	    ),
107	  };
108	};
